import { useEffect, useState } from "react";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [search, setSearch] = useState("");

    useEffect(() => {
        fetch("http://localhost:8000/leads")
            .then((res) => res.json())
            .then((data) => {
                console.log("API Response:", data);
                setLeads(data.leads || []);
            })
            .catch((err) => console.error("Error fetching leads:", err));
    }, []);

    // 🔍 Filtered Leads
    const filteredLeads = leads.filter((lead) =>
        Object.values(lead).some(
            (val) =>
                val &&
                val.toString().toLowerCase().includes(search.toLowerCase())
        )
    );

    return (
        <div className="container mt-4">
            <div className="card shadow-lg border-0 rounded-3">
                <div className="card-header d-flex justify-content-between align-items-center bg-primary text-white">
                    <h4 className="mb-0">📋 Leads</h4>
                    <input
                        type="text"
                        placeholder="🔍 Search..."
                        className="form-control form-control-sm w-25"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                    />
                </div>

                <div className="card-body p-0">
                    {filteredLeads.length > 0 ? (
                        <div className="table-responsive" style={{ maxHeight: "500px", overflowY: "auto" }}>
                            <table className="table table-hover table-bordered table-striped mb-0">
                                <thead className="table-dark sticky-top">
                                    <tr>
                                        <th>First Name</th>
                                        <th>Last Name</th>
                                        <th>Email</th>
                                        <th>Phone</th>
                                        <th>Company</th>
                                        <th>Domain</th>
                                        <th>Campaign</th>
                                        <th>Date</th>
                                        <th>Followed By</th>
                                        <th>Uploaded By</th>
                                        <th>Uploaded Date</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredLeads.map((lead) => (
                                        <tr key={lead.id}>
                                            <td>
                                                <span className="fw-bold text-primary">
                                                    {lead.first_name || "-"}
                                                </span>
                                            </td>
                                            <td>{lead.last_name || "-"}</td>
                                            <td>
                                                <span className="badge bg-info text-dark">
                                                    {lead.email || "-"}
                                                </span>
                                            </td>
                                            <td>
                                                <span className="badge bg-secondary">
                                                    {lead.phone || "-"}
                                                </span>
                                            </td>
                                            <td>{lead.company || "-"}</td>
                                            <td>{lead.domain || "-"}</td>
                                            <td>
                                                <span className="badge bg-success">
                                                    {lead.campaign || "-"}
                                                </span>
                                            </td>
                                            <td>{lead.date || "-"}</td>
                                            <td>{lead.followed_by || "-"}</td>
                                            <td>{lead.uploaded_by || "-"}</td>
                                            <td>{lead.uploaded_dt || "-"}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    ) : (
                        <p className="text-muted text-center p-3">
                            No leads found.
                        </p>
                    )}
                </div>
            </div>
        </div>
    );
}

export default Leads;
